--
-- Name: create_order_atomic(uuid, jsonb, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_order_atomic(p_restaurant_id uuid, p_items jsonb, p_payment_method text DEFAULT 'cash'::text, p_sync_metadata jsonb DEFAULT NULL::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order_id UUID;
    v_total_cents INTEGER := 0;
    v_total_tax_cents INTEGER := 0;
    v_item JSONB;
    v_item_total INTEGER;
    v_item_tax INTEGER;
    v_prod_id UUID;
    v_qty INTEGER;
    v_prod_name TEXT;
    v_unit_price INTEGER;
    v_table_id UUID;
    v_table_number INTEGER;
    v_prep_time_seconds INTEGER;
    v_prep_category TEXT;
    v_station TEXT;
    v_product_tax_rate_bps INTEGER;
    v_restaurant_default_tax INTEGER;
    v_effective_tax_rate INTEGER;
BEGIN
    -- Get restaurant default tax rate
    SELECT default_tax_rate_bps INTO v_restaurant_default_tax
    FROM public.gm_restaurants
    WHERE id = p_restaurant_id;

    IF v_restaurant_default_tax IS NULL THEN
        v_restaurant_default_tax := 2300; -- 23% fallback
    END IF;

    -- Extract table info from sync_metadata if provided
    IF p_sync_metadata IS NOT NULL THEN
        v_table_id := (p_sync_metadata->>'table_id')::UUID;
        v_table_number := (p_sync_metadata->>'table_number')::INTEGER;
    END IF;

    -- 1. Calculate Total Amount + Tax
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_prod_id := (v_item->>'product_id')::UUID;
        v_qty := (v_item->>'quantity')::INTEGER;
        v_unit_price := (v_item->>'unit_price')::INTEGER;
        v_item_total := v_qty * v_unit_price;

        -- Get product-specific tax rate (or use restaurant default)
        SELECT tax_rate_bps INTO v_product_tax_rate_bps
        FROM public.gm_products WHERE id = v_prod_id;

        v_effective_tax_rate := COALESCE(v_product_tax_rate_bps, v_restaurant_default_tax);

        -- Tax-inclusive calculation: tax = total - (total * 10000 / (10000 + rate))
        v_item_tax := v_item_total - (v_item_total * 10000 / (10000 + v_effective_tax_rate));

        v_total_cents := v_total_cents + v_item_total;
        v_total_tax_cents := v_total_tax_cents + v_item_tax;
    END LOOP;

    -- 2. Insert Order (Atomic)
    INSERT INTO public.gm_orders (
        restaurant_id,
        table_id,
        table_number,
        status,
        total_cents,
        subtotal_cents,
        tax_cents,
        payment_status,
        sync_metadata,
        origin,
        metadata
    )
    VALUES (
        p_restaurant_id,
        v_table_id,
        v_table_number,
        'OPEN',
        v_total_cents,
        v_total_cents - v_total_tax_cents,
        v_total_tax_cents,
        'PENDING',
        p_sync_metadata,
        COALESCE((p_sync_metadata->>'origin')::TEXT, 'CAIXA'),
        jsonb_build_object('payment_method', p_payment_method)
    )
    RETURNING id INTO v_order_id;

    -- 3. Insert Order Items (with tax snapshot + prep time + authorship)
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_prod_id := (v_item->>'product_id')::UUID;
        v_prod_name := v_item->>'name';
        v_qty := (v_item->>'quantity')::INTEGER;
        v_unit_price := (v_item->>'unit_price')::INTEGER;
        v_item_total := v_qty * v_unit_price;

        -- Fetch prep_time, station, and tax_rate from product
        SELECT prep_time_seconds, prep_category, station, tax_rate_bps
        INTO v_prep_time_seconds, v_prep_category, v_station, v_product_tax_rate_bps
        FROM public.gm_products
        WHERE id = v_prod_id;

        v_prep_time_seconds := COALESCE(v_prep_time_seconds, 300);
        v_prep_category := COALESCE(v_prep_category, 'main');
        v_station := COALESCE(v_station, 'KITCHEN');
        v_effective_tax_rate := COALESCE(v_product_tax_rate_bps, v_restaurant_default_tax);

        -- Tax per line item (tax-inclusive)
        v_item_tax := v_item_total - (v_item_total * 10000 / (10000 + v_effective_tax_rate));

        INSERT INTO public.gm_order_items (
            order_id,
            product_id,
            name_snapshot,
            price_snapshot,
            quantity,
            subtotal_cents,
            tax_rate_bps,
            tax_cents,
            prep_time_seconds,
            prep_category,
            station,
            created_by_user_id,
            created_by_role,
            device_id
        )
        VALUES (
            v_order_id,
            v_prod_id,
            v_prod_name,
            v_unit_price,
            v_qty,
            v_item_total,
            v_effective_tax_rate,
            v_item_tax,
            v_prep_time_seconds,
            v_prep_category,
            v_station,
            (v_item->>'created_by_user_id')::UUID,
            v_item->>'created_by_role',
            v_item->>'device_id'
        );
    END LOOP;

    -- 4. Return Created Order
    RETURN jsonb_build_object(
        'id', v_order_id,
        'total_cents', v_total_cents,
        'subtotal_cents', v_total_cents - v_total_tax_cents,
        'tax_cents', v_total_tax_cents,
        'status', 'OPEN'
    );
EXCEPTION
    WHEN unique_violation THEN
        RAISE EXCEPTION 'TABLE_HAS_ACTIVE_ORDER: Esta mesa já possui um pedido aberto';
END;
$$;


ALTER FUNCTION public.create_order_atomic(p_restaurant_id uuid, p_items jsonb, p_payment_method text, p_sync_metadata jsonb) OWNER TO postgres;

--
-- Name: FUNCTION create_order_atomic(p_restaurant_id uuid, p_items jsonb, p_payment_method text, p_sync_metadata jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.create_order_atomic(p_restaurant_id uuid, p_items jsonb, p_payment_method text, p_sync_metadata jsonb) IS 'Official Core RPC: Creates order atomically with IVA tax calculation. Tax-inclusive pricing (EU standard). Enforces constitutional constraints.';


--
-- Name: create_tables_from_capacity(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_tables_from_capacity(p_restaurant_id uuid, p_capacity integer, p_tables_per_zone integer DEFAULT 5) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_tables_created INTEGER := 0;
  v_table_number INTEGER;
  v_zone_id UUID;
BEGIN
  -- Verificar se já existem mesas
  IF EXISTS (SELECT 1 FROM public.gm_tables WHERE restaurant_id = p_restaurant_id) THEN
    RETURN 0; -- Já existem mesas, não criar
  END IF;

  -- Criar mesas baseado na capacidade (assumindo 4 pessoas por mesa)
  FOR v_table_number IN 1..(p_capacity / 4) LOOP
    INSERT INTO public.gm_tables (restaurant_id, number, status)
    VALUES (p_restaurant_id, v_table_number, 'closed')
    ON CONFLICT (restaurant_id, number) DO NOTHING;
    
    v_tables_created := v_tables_created + 1;
  END LOOP;

  RETURN v_tables_created;
END;
$$;


ALTER FUNCTION public.create_tables_from_capacity(p_restaurant_id uuid, p_capacity integer, p_tables_per_zone integer) OWNER TO postgres;

