-- Name: FUNCTION create_tables_from_capacity(p_restaurant_id uuid, p_capacity integer, p_tables_per_zone integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.create_tables_from_capacity(p_restaurant_id uuid, p_capacity integer, p_tables_per_zone integer) IS 'Cria mesas automaticamente baseado na capacidade do restaurante';


--
-- Name: current_user_restaurants(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.current_user_restaurants() RETURNS TABLE(restaurant_id uuid)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT DISTINCT ru.restaurant_id
  FROM restaurant_users ru
  WHERE ru.user_id = auth.uid()
    AND ru.deleted_at IS NULL

  UNION ALL

  SELECT (auth.jwt() ->> 'restaurant_id')::uuid
  WHERE (auth.jwt() ->> 'restaurant_id') IS NOT NULL;
$$;


ALTER FUNCTION public.current_user_restaurants() OWNER TO postgres;

--
-- Name: deduct_stock_by_bom(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.deduct_stock_by_bom(p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order RECORD;
    v_item RECORD;
    v_bom RECORD;
    v_location_id UUID;
    v_current_qty NUMERIC;
    v_min_qty NUMERIC;
    v_deduction NUMERIC;
    v_deductions_count INTEGER := 0;
    v_low_stock_alerts JSONB := '[]'::jsonb;
BEGIN
    -- Get order info
    SELECT id, restaurant_id, status
    INTO v_order
    FROM public.gm_orders
    WHERE id = p_order_id;

    IF v_order IS NULL THEN
        RAISE EXCEPTION 'ORDER_NOT_FOUND: Order % not found', p_order_id;
    END IF;

    -- Only deduct for CLOSED orders (safety check)
    IF v_order.status != 'CLOSED' THEN
        RAISE EXCEPTION 'ORDER_NOT_CLOSED: Cannot deduct stock for order with status %', v_order.status;
    END IF;

    -- Iterate order items
    FOR v_item IN
        SELECT oi.id AS item_id, oi.product_id, oi.quantity
        FROM public.gm_order_items oi
        WHERE oi.order_id = p_order_id
          AND oi.product_id IS NOT NULL
    LOOP
        -- Iterate BOM entries for this product
        FOR v_bom IN
            SELECT b.ingredient_id, b.qty_per_unit, b.station, b.preferred_location_kind
            FROM public.gm_product_bom b
            WHERE b.product_id = v_item.product_id
              AND b.restaurant_id = v_order.restaurant_id
        LOOP
            v_deduction := v_bom.qty_per_unit * v_item.quantity;

            -- Find best stock location: prefer by kind, fallback to any with stock
            SELECT sl.id, sl.location_id, sl.qty
            INTO v_location_id, v_location_id, v_current_qty
            FROM public.gm_stock_levels sl
            JOIN public.gm_locations loc ON loc.id = sl.location_id
            WHERE sl.restaurant_id = v_order.restaurant_id
              AND sl.ingredient_id = v_bom.ingredient_id
              AND sl.qty > 0
            ORDER BY
                CASE WHEN loc.kind = COALESCE(v_bom.preferred_location_kind, v_bom.station) THEN 0 ELSE 1 END,
                sl.qty DESC
            LIMIT 1;

            -- If we found stock, deduct
            IF v_location_id IS NOT NULL THEN
                -- Deduct from stock_levels
                UPDATE public.gm_stock_levels
                SET qty = qty - v_deduction,
                    updated_at = NOW()
                WHERE restaurant_id = v_order.restaurant_id
                  AND location_id = v_location_id
                  AND ingredient_id = v_bom.ingredient_id;

                -- Log to ledger
                INSERT INTO public.gm_stock_ledger (
                    restaurant_id, location_id, ingredient_id,
                    order_id, order_item_id,
                    action, qty, reason,
                    created_by_role
                ) VALUES (
                    v_order.restaurant_id, v_location_id, v_bom.ingredient_id,
                    p_order_id, v_item.item_id,
                    'CONSUME', v_deduction,
                    'Order closed: auto BOM deduction',
                    'system'
                );

                v_deductions_count := v_deductions_count + 1;

                -- Check for low stock alert after deduction
                SELECT sl2.qty, sl2.min_qty
                INTO v_current_qty, v_min_qty
                FROM public.gm_stock_levels sl2
                WHERE sl2.restaurant_id = v_order.restaurant_id
                  AND sl2.location_id = v_location_id
                  AND sl2.ingredient_id = v_bom.ingredient_id;

                IF v_current_qty <= v_min_qty AND v_min_qty > 0 THEN
                    v_low_stock_alerts := v_low_stock_alerts || jsonb_build_object(
                        'ingredient_id', v_bom.ingredient_id,
                        'location_id', v_location_id,
                        'current_qty', v_current_qty,
                        'min_qty', v_min_qty
                    );
                END IF;

            ELSE
                -- No stock found — log as zero-stock consume anyway for audit
                -- Find any location for this restaurant
                SELECT loc.id INTO v_location_id
                FROM public.gm_locations loc
                WHERE loc.restaurant_id = v_order.restaurant_id
                ORDER BY
                    CASE WHEN loc.kind = COALESCE(v_bom.preferred_location_kind, v_bom.station) THEN 0 ELSE 1 END
                LIMIT 1;

                IF v_location_id IS NOT NULL THEN
                    INSERT INTO public.gm_stock_ledger (
                        restaurant_id, location_id, ingredient_id,
                        order_id, order_item_id,
                        action, qty, reason,
                        created_by_role
                    ) VALUES (
                        v_order.restaurant_id, v_location_id, v_bom.ingredient_id,
                        p_order_id, v_item.item_id,
                        'CONSUME', v_deduction,
                        'Order closed: auto BOM deduction (NO STOCK AVAILABLE)',
                        'system'
                    );
                END IF;
            END IF;
        END LOOP;
    END LOOP;

    RETURN jsonb_build_object(
        'success', true,
        'order_id', p_order_id,
        'deductions_count', v_deductions_count,
        'low_stock_alerts', v_low_stock_alerts
    );
END;
$$;


ALTER FUNCTION public.deduct_stock_by_bom(p_order_id uuid) OWNER TO postgres;

--
-- Name: FUNCTION deduct_stock_by_bom(p_order_id uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.deduct_stock_by_bom(p_order_id uuid) IS 'Core RPC: Deducts ingredients from stock based on product BOM when order closes. Logs to gm_stock_ledger and flags low-stock alerts.';


--
-- Name: disable_audit_mode(uuid, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.disable_audit_mode(p_restaurant_id uuid, p_reason text DEFAULT 'audit_closed'::text, p_reason_detail text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_id UUID;
BEGIN
    -- Only manager/owner can disable audit mode
    PERFORM public.require_restaurant_role(
        p_restaurant_id,
        ARRAY['owner', 'manager']
    );

    UPDATE public.gm_audit_mode
    SET
        status = 'DISABLED',
        disabled_by = auth.uid(),
        disabled_at = NOW(),
        reason = p_reason,
        reason_detail = p_reason_detail,
        metadata = COALESCE(p_metadata, '{}'::jsonb)
    WHERE restaurant_id = p_restaurant_id
      AND status = 'ENABLED'
    RETURNING id INTO v_id;

    RETURN jsonb_build_object(
        'id', v_id,
        'status', 'DISABLED'
    );
END;
$$;


ALTER FUNCTION public.disable_audit_mode(p_restaurant_id uuid, p_reason text, p_reason_detail text, p_metadata jsonb) OWNER TO postgres;

--
-- Name: emit_order_created_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.emit_order_created_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_next_version INTEGER;
BEGIN
  SELECT COALESCE(MAX(stream_version), 0) + 1
    INTO v_next_version
    FROM public.event_store
   WHERE stream_type = 'ORDER'
     AND stream_id = NEW.id::text;

  INSERT INTO public.event_store (
    event_id,
    stream_type,
    stream_id,
    stream_version,
    event_type,
    payload,
    meta
  ) VALUES (
    gen_random_uuid(),
    'ORDER',
    NEW.id::text,
    v_next_version,
    'ORDER_CREATED',
    jsonb_build_object(
      'orderId', NEW.id,
      'restaurantId', NEW.restaurant_id,
      'totalCents', NEW.total_cents,
      'status', NEW.status,
      'paymentStatus', NEW.payment_status,
      'source', NEW.source
    ),
    jsonb_build_object('schema_version', '1')
  );

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.emit_order_created_event() OWNER TO postgres;

--
-- Name: emit_order_paid_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.emit_order_paid_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_next_version INTEGER;
    v_order_total INTEGER;
    v_total_paid BIGINT;
BEGIN
    -- Only emit for successful payments
    IF NEW.status != 'paid' THEN
        RETURN NEW;
    END IF;

    -- Get order total for context
    SELECT total_cents INTO v_order_total
    FROM public.gm_orders
    WHERE id = NEW.order_id;

    -- Calculate total paid so far
    SELECT COALESCE(SUM(amount_cents), 0) INTO v_total_paid
    FROM public.gm_payments
    WHERE order_id = NEW.order_id
      AND status = 'paid';

    SELECT COALESCE(MAX(stream_version), 0) + 1
    INTO v_next_version
    FROM public.event_store
    WHERE stream_type = 'PAYMENT'
      AND stream_id = NEW.order_id::text;

    INSERT INTO public.event_store (
        event_id, stream_type, stream_id, stream_version,
        event_type, payload, meta
    ) VALUES (
        gen_random_uuid(),
        'PAYMENT',
        NEW.order_id::text,
        v_next_version,
        'ORDER_PAID',
        jsonb_build_object(
            'paymentId', NEW.id,
            'orderId', NEW.order_id,
            'restaurantId', NEW.restaurant_id,
            'amountCents', NEW.amount_cents,
            'paymentMethod', NEW.payment_method,
            'currency', NEW.currency,
            'cashRegisterId', NEW.cash_register_id,
            'orderTotalCents', v_order_total,
            'totalPaidCents', v_total_paid,
            'isFullyPaid', v_total_paid >= v_order_total
        ),
        jsonb_build_object('schema_version', '1')
    );

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.emit_order_paid_event() OWNER TO postgres;

