        v_next_version,
        'ORDER_STATUS_CHANGED',
        jsonb_build_object(
            'orderId', NEW.id,
            'restaurantId', NEW.restaurant_id,
            'oldStatus', OLD.status,
            'newStatus', NEW.status,
            'totalCents', NEW.total_cents,
            'taxCents', NEW.tax_cents,
            'tableId', NEW.table_id
        ),
        jsonb_build_object('schema_version', '1')
