--
-- Name: emit_product_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.emit_product_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_event_type TEXT;
  v_payload    JSONB;
  v_version    INTEGER;
BEGIN
  -- Determine event type
  IF TG_OP = 'INSERT' THEN
    v_event_type := 'PRODUCT_CREATED';
  ELSIF TG_OP = 'UPDATE' THEN
    v_event_type := 'PRODUCT_UPDATED';
  ELSIF TG_OP = 'DELETE' THEN
    v_event_type := 'PRODUCT_DELETED';
  END IF;

  -- Build payload
  IF TG_OP = 'DELETE' THEN
    v_payload := jsonb_build_object(
      'product_id',    OLD.id,
      'restaurant_id', OLD.restaurant_id,
      'name',          OLD.name,
      'deleted_at',    now()
    );
  ELSE
    v_payload := jsonb_build_object(
      'product_id',    NEW.id,
      'restaurant_id', NEW.restaurant_id,
      'category_id',   NEW.category_id,
      'name',          NEW.name,
      'description',   NEW.description,
      'price_cents',   NEW.price_cents,
      'photo_url',     NEW.photo_url,
      'available',     NEW.available
    );
  END IF;

  -- Get next stream version for this product
  SELECT COALESCE(MAX(stream_version), 0) + 1
    INTO v_version
    FROM event_store
   WHERE stream_type = 'PRODUCT'
     AND stream_id   = COALESCE(NEW.id, OLD.id)::TEXT;

  -- Insert event
  INSERT INTO event_store (event_id, stream_type, stream_id, stream_version, event_type, payload, meta, created_at)
  VALUES (
    gen_random_uuid(),
    'PRODUCT',
    COALESCE(NEW.id, OLD.id)::TEXT,
    v_version,
    v_event_type,
    v_payload,
    jsonb_build_object('trigger', 'sync_products_to_catalog', 'source', 'db_trigger'),
    now()
  );

  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION public.emit_product_event() OWNER TO postgres;

