--
-- Name: enable_audit_mode(uuid, text, text, timestamp with time zone, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.enable_audit_mode(p_restaurant_id uuid, p_reason text DEFAULT 'audit_requested'::text, p_reason_detail text DEFAULT NULL::text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_metadata jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_id UUID;
BEGIN
    -- Only manager/owner can enable audit mode
    PERFORM public.require_restaurant_role(
        p_restaurant_id,
        ARRAY['owner', 'manager']
    );

    INSERT INTO public.gm_audit_mode (
        restaurant_id, status, reason, reason_detail,
        enabled_by, enabled_at, expires_at, metadata
    ) VALUES (
        p_restaurant_id, 'ENABLED', p_reason, p_reason_detail,
        auth.uid(), NOW(), p_expires_at, COALESCE(p_metadata, '{}'::jsonb)
    )
    RETURNING id INTO v_id;

    RETURN jsonb_build_object(
        'id', v_id,
        'status', 'ENABLED'
    );
END;
$$;


