-- Name: FUNCTION get_daily_metrics(p_restaurant_id uuid, p_timezone text); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_daily_metrics(p_restaurant_id uuid, p_timezone text) IS 'Dashboard RPC: métricas diárias (receita, pedidos, ticket médio, faturamento/hora).';


--
-- Name: get_fiscal_certification_status(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_fiscal_certification_status(p_restaurant_id uuid, p_jurisdiction text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_result JSONB;
BEGIN
    -- Role gate: authenticated with restaurant access
    PERFORM require_restaurant_role(p_restaurant_id, ARRAY['staff', 'waiter', 'kitchen', 'manager', 'owner']);

    SELECT jsonb_agg(jsonb_build_object(
        'id',           fc.id,
        'jurisdiction',  fc.jurisdiction,
        'status',        fc.status,
        'requested_at',  fc.requested_at,
        'submitted_at',  fc.submitted_at,
        'approved_at',   fc.approved_at,
        'rejected_at',   fc.rejected_at,
        'checklist',     fc.checklist,
        'notes',         fc.notes,
        'signature_data', fc.signature_data,
        'updated_at',    fc.updated_at
    ) ORDER BY fc.requested_at DESC)
    INTO v_result
    FROM public.gm_fiscal_certifications fc
    WHERE fc.restaurant_id = p_restaurant_id
      AND (p_jurisdiction IS NULL OR fc.jurisdiction = p_jurisdiction);

    RETURN COALESCE(v_result, '[]'::jsonb);
END;
$$;


