-- Name: request_export_job(uuid, text, text, timestamp with time zone, timestamp with time zone, jsonb, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.request_export_job(p_restaurant_id uuid, p_export_type text, p_format text DEFAULT 'CSV'::text, p_filter_from timestamp with time zone DEFAULT NULL::timestamp with time zone, p_filter_to timestamp with time zone DEFAULT NULL::timestamp with time zone, p_parameters jsonb DEFAULT '{}'::jsonb, p_idempotency_key text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_id UUID;
BEGIN
    -- Only manager/owner can request exports
    PERFORM public.require_restaurant_role(
        p_restaurant_id,
        ARRAY['owner', 'manager']
    );

    IF p_idempotency_key IS NOT NULL THEN
        SELECT id INTO v_id
        FROM public.gm_export_jobs
        WHERE idempotency_key = p_idempotency_key;

        IF v_id IS NOT NULL THEN
            RETURN jsonb_build_object('id', v_id, 'status', 'QUEUED', 'idempotent', true);
        END IF;
    END IF;

    INSERT INTO public.gm_export_jobs (
        restaurant_id, export_type, format, status,
        requested_by, filter_from, filter_to, parameters, idempotency_key
    ) VALUES (
        p_restaurant_id, p_export_type, p_format, 'QUEUED',
        auth.uid(), p_filter_from, p_filter_to, COALESCE(p_parameters, '{}'::jsonb), p_idempotency_key
    ) RETURNING id INTO v_id;

    RETURN jsonb_build_object('id', v_id, 'status', 'QUEUED');
END;
$$;


