-- Name: request_fiscal_certification(uuid, text, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.request_fiscal_certification(p_restaurant_id uuid, p_jurisdiction text DEFAULT 'GENERIC'::text, p_checklist jsonb DEFAULT '{}'::jsonb, p_notes text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_id UUID;
    v_existing UUID;
BEGIN
    -- Role gate: only manager/owner can request
    PERFORM require_restaurant_role(p_restaurant_id, ARRAY['manager', 'owner']);

    -- Idempotency check
    IF p_idempotency_key IS NOT NULL THEN
        SELECT id INTO v_existing
        FROM public.gm_fiscal_certifications
        WHERE idempotency_key = p_idempotency_key;

        IF v_existing IS NOT NULL THEN
            RETURN jsonb_build_object(
                'id', v_existing,
                'status', 'IDEMPOTENT_HIT',
                'message', 'Certification request already exists'
            );
        END IF;
    END IF;

    INSERT INTO public.gm_fiscal_certifications (
        restaurant_id, jurisdiction, status,
        requested_by, requested_at,
        checklist, notes, idempotency_key
    ) VALUES (
        p_restaurant_id, p_jurisdiction, 'REQUESTED',
        auth.uid(), NOW(),
        p_checklist, p_notes, p_idempotency_key
    )
    RETURNING id INTO v_id;

    RETURN jsonb_build_object(
        'id', v_id,
        'status', 'REQUESTED',
        'jurisdiction', p_jurisdiction
    );
END;
$$;


