--
-- Name: require_authenticated(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.require_authenticated() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF current_setting('role', true) = 'anon' THEN
        RAISE EXCEPTION 'AUTH_REQUIRED: This operation requires authentication'
            USING ERRCODE = '42501'; -- insufficient_privilege
    END IF;
END;
$$;


ALTER FUNCTION public.require_authenticated() OWNER TO postgres;

--
-- Name: require_restaurant_role(uuid, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.require_restaurant_role(p_restaurant_id uuid, p_required_roles text[] DEFAULT ARRAY['owner'::text, 'manager'::text]) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_role TEXT;
BEGIN
    -- service_role always passes
    IF current_setting('role', true) = 'service_role' THEN
        RETURN;
    END IF;

    -- Check user has required role for this restaurant
    SELECT role INTO v_user_role
    FROM public.restaurant_users
    WHERE user_id = auth.uid()
      AND restaurant_id = p_restaurant_id
      AND deleted_at IS NULL
      AND active = true;

    IF v_user_role IS NULL THEN
        RAISE EXCEPTION 'ACCESS_DENIED: No access to restaurant %', p_restaurant_id
            USING ERRCODE = '42501';
    END IF;

    IF v_user_role != ALL(p_required_roles) THEN
        RAISE EXCEPTION 'INSUFFICIENT_ROLE: Requires % but has %',
            array_to_string(p_required_roles, '/'), v_user_role
            USING ERRCODE = '42501';
    END IF;
END;
$$;


ALTER FUNCTION public.require_restaurant_role(p_restaurant_id uuid, p_required_roles text[]) OWNER TO postgres;

--
-- Name: simulate_order_stock_impact(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.simulate_order_stock_impact(p_restaurant_id uuid, p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
BEGIN
  WITH req AS (
    SELECT
      (i->>'product_id')::UUID AS product_id,
      COALESCE((i->>'quantity')::INT, 1) AS qty
    FROM jsonb_array_elements(p_items) i
  ),
  needed AS (
    SELECT
      b.ingredient_id,
      b.station,
      SUM(b.qty_per_unit * r.qty) AS needed_qty
    FROM req r
    JOIN public.gm_product_bom b
      ON b.product_id = r.product_id AND b.restaurant_id = p_restaurant_id
    GROUP BY b.ingredient_id, b.station
  ),
  stock AS (
    SELECT
      sl.ingredient_id,
      SUM(sl.qty) AS available_qty,
      SUM(sl.min_qty) AS min_total
    FROM public.gm_stock_levels sl
    WHERE sl.restaurant_id = p_restaurant_id
    GROUP BY sl.ingredient_id
  )
  SELECT jsonb_agg(jsonb_build_object(
    'ingredient_id', n.ingredient_id,
    'needed_qty', n.needed_qty,
    'available_qty', COALESCE(s.available_qty, 0),
    'will_be', COALESCE(s.available_qty, 0) - n.needed_qty,
    'below_min', (COALESCE(s.available_qty, 0) - n.needed_qty) < COALESCE(s.min_total, 0),
    'station', n.station
  ))
  INTO v_result
  FROM needed n
  LEFT JOIN stock s ON s.ingredient_id = n.ingredient_id;

  RETURN COALESCE(v_result, '[]'::JSONB);
END;
$$;


