-- Name: trg_deduct_stock_on_close(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trg_deduct_stock_on_close() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Only fire when transitioning TO CLOSED
    IF NEW.status = 'CLOSED' AND OLD.status != 'CLOSED' THEN
        PERFORM public.deduct_stock_by_bom(NEW.id);
    END IF;
    RETURN NEW;
END;
$$;


