--
-- Name: restaurant_users restaurant_users_insert_manager; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY restaurant_users_insert_manager ON public.restaurant_users FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1
   FROM public.restaurant_users ru
  WHERE ((ru.user_id = auth.uid()) AND (ru.restaurant_id = restaurant_users.restaurant_id) AND (ru.role = ANY (ARRAY['owner'::text, 'manager'::text])) AND (ru.deleted_at IS NULL)))));


--
